    {
      "keystrokes": "python3 - << 'PY'
import subprocess
from pathlib import Path

# Read FASTA
f = Path('sequences.fasta').read_text().strip().splitlines()
seqs = {}
name = None
buf = []
for line in f:
    if line.startswith('>'):
        if name:
            seqs[name] = ''.join(buf).replace('\n','').replace('\r','').upper()
        name = line[1:].strip().split()[0]
        buf = []
    else:
        buf.append(line.strip())
if name:
    seqs[name] = ''.join(buf).upper()

# Helpers
comp = str.maketrans('ACGTN','TGCAN')
def rc(s):
    return s.translate(comp)[::-1]

def oligotm_tm(seq):
    flags = ['-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500']
    p = subprocess.run(['oligotm'] + flags, input=seq.encode(), stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    out = p.stdout.decode().strip()
    try:
        return float(out)
    except Exception:
        return None

out = seqs['output']
input_plasmid = seqs['input']
ins_names = ['egfp','flag','snap']
ins = {k: seqs[k] for k in ins_names}

# Diagnostics
print('Lengths:')
for k,v in seqs.items():
    print(k, len(v))

# Locate inserts in output (fwd or rc)
placements = []
for k, v in ins.items():
    p = out.find(v)
    prc = out.find(rc(v))
    print(f'{k} fwd_pos={p} rc_pos={prc}')
    if p != -1:
        placements.append((p, k, '+', v))
    elif prc != -1:
        placements.append((prc, k, '-', rc(v)))
    else:
        raise SystemExit(f'Insert {k} not found in output')
placements.sort()
print('Ordered placements:', [(p,k,s) for p,k,s,_ in placements])

# Determine backbone interval in output between last and first insert (circular wrap)
last_start, last_name, last_strand, last_seq = placements[-1]
first_start, first_name, first_strand, first_seq = placements[0]
last_end = last_start + len(last_seq)
backbone_out = out[last_end:] + out[:first_start]
print('Backbone_out length:', len(backbone_out))

# Find backbone_out in input (circular)
circ_inp = input_plasmid + input_plasmid
pos_inp = circ_inp.find(backbone_out)
backbone_orient = '+'
if pos_inp == -1:
    pos_inp = circ_inp.find(rc(backbone_out))
    if pos_inp != -1:
        backbone_orient = '-'
print('Backbone found in input at', pos_inp, 'orient', backbone_orient)

# Prepare fragment sequences in assembly orientation
frags = []
back_seq = backbone_out if backbone_orient == '+' else rc(backbone_out)
frags.append(('input', back_seq))
for _, name, strand, oriented_seq in placements:
    frags.append((name, oriented_seq))

# Define overhangs from output sequence
# Compute the 4-bp left overhang for each fragment as the first 4 nt of its region in output
# For backbone, left overhang = first 4 nt of backbone_out in output context (start is last_end)
L = len(out)
back_start_out = last_end % L
def slice_out(start, n):
    if start + n <= L:
        return out[start:start+n]
    else:
        k = (start + n) % L
        return out[start:] + out[:k]

overhangs_left = {}
overhangs_right = {}
overhangs_left['input'] = slice_out(back_start_out, 4)
# Map names to their start indices in output
start_idx = {name: p for p,name,_,_ in placements}
for p, name, strand, oriented_seq in placements:
    overhangs_left[name] = out[p:p+4]

# Right overhang of each fragment is the left overhang of the next fragment in circular order
order = ['input'] + [name for _,name,_,_ in placements]
for i, frag in enumerate(order):
    nxt = order[(i+1)%len(order)]
    overhangs_right[frag] = overhangs_left[nxt]

# Check uniqueness of overhangs
seen = {}
for frag in order:
    oh = overhangs_right[frag]
    seen.setdefault(oh, []).append(frag)
if any(len(v)>1 for v in seen.values()):
    print('Warning: duplicate overhangs present:', {k:v for k,v in seen.items() if len(v)>1})

# Primer design with BsaI-HFv2: 5' padding + GGTCTC + overhang + anneal (rev uses rc of right overhang)
PAD = 'GCAT'

# Design annealing regions per fragment to meet Tm constraints
results = []
for frag_name, templ in frags:
    f_len = 20
    r_len = 20
    best = None
    for _ in range(400):
        f_anneal = templ[:f_len]
        r_anneal = rc(templ[-r_len:])
        f_tm = oligotm_tm(f_anneal)
        r_tm = oligotm_tm(r_anneal)
        if f_tm is None or r_tm is None:
            f_len = min(f_len+1,45)
            r_len = min(r_len+1,45)
            continue
        # adjust into 58-72
        changed = False
        if f_tm < 58 and f_len < 45:
            f_len += 1; changed=True
        elif f_tm > 72 and f_len > 15:
            f_len -= 1; changed=True
        if r_tm < 58 and r_len < 45:
            r_len += 1; changed=True
        elif r_tm > 72 and r_len > 15:
            r_len -= 1; changed=True
        if changed:
            continue
        # keep within 5C
        if abs(f_tm - r_tm) > 5:
            if f_tm < r_tm and f_len < 45:
                f_len += 1
            elif f_tm > r_tm and f_len > 15:
                f_len -= 1
            if r_tm < f_tm and r_len < 45:
                r_len += 1
            elif r_tm > f_tm and r_len > 15:
                r_len -= 1
            continue
        best = (f_anneal, r_anneal, f_tm, r_tm)
        break
    if best is None:
        f_anneal = templ[:max(15,min(45,f_len))]
        r_anneal = rc(templ[-max(15,min(45,r_len)):])
        f_tm = oligotm_tm(f_anneal)
        r_tm = oligotm_tm(r_anneal)
    else:
        f_anneal, r_anneal, f_tm, r_tm = best
    left_oh = overhangs_left[frag_name]
    right_oh = overhangs_right[frag_name]
    fwd_primer = PAD + 'GGTCTC' + left_oh + f_anneal
    rev_primer = PAD + 'GGTCTC' + rc(right_oh) + r_anneal
    results.append((frag_name, 'fwd', fwd_primer, f_tm))
    results.append((frag_name, 'rev', rev_primer, r_tm))

# Write primers.fasta
with open('primers.fasta', 'w') as fh:
    for name, dirn, seq, tm in results:
        fh.write(f'>{name}_{dirn}\n')
        fh.write(seq + '\n')

print('Primers designed:')
for name, dirn, seq, tm in results:
    print(f'{name}_{dirn} Tm={tm:.2f}C')
